import { useState, useEffect } from "react";

const LOGO_SRC = "data:image/png;base64,";

export default function SplashScreen({ onComplete }) {
  const [phase, setPhase] = useState("enter"); // enter -> hold -> exit

  useEffect(() => {
    const t1 = setTimeout(() => setPhase("hold"), 800);
    const t2 = setTimeout(() => setPhase("exit"), 3500);
    const t3 = setTimeout(() => onComplete(), 4400);
    return () => [t1, t2, t3].forEach(clearTimeout);
  }, []);

  const isExiting = phase === "exit";

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      background: "linear-gradient(135deg, #f9c6d0 0%, #f4a7b9 40%, #e8799a 100%)",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      opacity: isExiting ? 0 : 1,
      transition: "opacity 0.9s ease",
      overflow: "hidden",
    }}>

      {/* Soft radial glow behind logo */}
      <div style={{
        position: "absolute",
        width: 500, height: 500,
        borderRadius: "50%",
        background: "radial-gradient(circle, rgba(255,255,255,0.45) 0%, transparent 70%)",
        transform: "translateY(-20px)",
        pointerEvents: "none",
      }} />

      {/* Floating petal dots */}
      {[...Array(14)].map((_, i) => (
        <div key={i} style={{
          position: "absolute",
          width: 8 + (i % 4) * 4,
          height: 8 + (i % 4) * 4,
          borderRadius: "50%",
          background: `rgba(255,255,255,${0.15 + (i % 3) * 0.1})`,
          left: `${5 + (i * 67) % 90}%`,
          top: `${10 + (i * 53) % 80}%`,
          animation: `float${i % 3} ${3 + (i % 3)}.{i % 9}s ease-in-out infinite`,
          pointerEvents: "none",
        }} />
      ))}

      {/* Logo */}
      <div style={{
        opacity: phase === "enter" ? 0 : 1,
        transform: phase === "enter" ? "scale(0.88)" : "scale(1)",
        transition: "opacity 1s ease, transform 1s ease",
        textAlign: "center",
        position: "relative", zIndex: 2,
      }}>
        <img
          src={LOGO_SRC}
          alt="Pretty Petals"
          style={{
            width: "min(360px, 80vw)",
            filter: "drop-shadow(0 4px 24px rgba(180,80,100,0.25))",
          }}
        />
        <div style={{
          marginTop: 12,
          opacity: phase === "hold" ? 1 : 0,
          transition: "opacity 1.2s ease 0.3s",
          fontSize: 14,
          letterSpacing: "0.25em",
          color: "rgba(120,50,65,0.75)",
          fontFamily: "Georgia, serif",
          textTransform: "uppercase",
        }}>
          Houston, Texas
        </div>
      </div>

      <style>{`
        @keyframes float0 { 0%,100% { transform: translateY(0px); } 50% { transform: translateY(-12px); } }
        @keyframes float1 { 0%,100% { transform: translateY(0px); } 50% { transform: translateY(-18px); } }
        @keyframes float2 { 0%,100% { transform: translateY(0px); } 50% { transform: translateY(-8px); } }
      `}</style>
    </div>
  );
}
